]}},{"name":"podcast","type":"object","required":false,"description":"Podcast episode content","fields":[{"name":"episode_title","type":"string","required":false,"description":"Episode title"},{"name":"episode_description","type":"string","required":false,"description":"Episode description — verify hook matches intro_hook"},{"name":"intro_hook","type":"string","required":false,"description":"Opening hook — verify 1st or 2nd person framing"},{"name":"talking_points","type":"array","required":false,"description":"Episode talking points with notes","items":{"type":"object","fields":[{"name":"point","type":"string","required":true,"description":"Talking point"},{"name":"notes","type":"string","required":true,"description":"Supporting notes"}]}},{"name":"host_talking_prompts","type":"array","required":false,"description":"Invitation prompts for host — verify none are fabricated first-person claims","items":{"type":"string"}},{"name":"guest_questions","type":"array","required":false,"description":"Guest interview questions","items":{"type":"string"}},{"name":"outro","type":"string","required":false,"description":"Closing remarks — verify contains a subscribe/follow CTA verb"},{"name":"duration_estimate","type":"string","required":false,"description":"Rough duration estimate"}]},{"name":"engagement","type":"object","required":false,"description":"Engagement assets","fields":[{"name":"pinned_comment","type":"string","required":false,"description":"YouTube pinned comment"},{"name":"community_post","type":"string","required":false,"description":"Community post content"},{"name":"hook_tweet","type":"string","required":false,"description":"Opening tweet of Twitter thread"},{"name":"thread_outline","type":"array","required":false,"description":"Supporting tweets in the thread","items":{"type":"string"}}]}]}]},"outputSchema":{"name":"BC_REVIEW_OUTPUT","fields":[{"name":"idea_id","type":"string","required":true,"description":"The idea identifier"},{"name":"overall_verdict","type":