fields":[{"name":"location","type":"string","required":true,"description":"Section/paragraph reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}}]},{"name":"seo_check","type":"object","required":false,"description":"SEO analysis","fields":[{"name":"title_optimized","type":"boolean","required":true,"description":"Whether title is optimized"},{"name":"meta_description_optimized","type":"boolean","required":true,"description":"Whether meta description is optimized"},{"name":"keyword_usage","type":"string","required":true,"description":"Keyword usage assessment: good | needs_improvement | poor"},{"name":"readability_score","type":"string","required":true,"description":"Readability: easy | moderate | difficult"}]},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"video_review","type":"object","required":false,"description":"Video content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"strengths","type":"array","required":false,"description":"Key strengths of the video","items":{"type":"string"}},{"name":"issues","type":"object","required":false,"description":"Issues found","fields":[{"name":"critical","type":"array","required":false,"description":"Critical issues","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Timestamp/section reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}},{"name":"minor","type":"array","required":false,"description":"Minor issues","items":{"type":"object","fields":[{"name":"location","type":"string","required":true,"description":"Timestamp/section reference"},{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}}]},{"name":"hook_effectiveness","type":"string","required":false,"description":"Hook effectiveness: strong | moderate | weak"},{"name":"pacing_notes","type":"string","required":false,"description":"Notes on video pacing"},{"name":"thumbnail_feedback","type":"string","required":false,"description":"Feedback on thumbnail"},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"shorts_review","type":"object","required":false,"description":"Shorts content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"individual_reviews","type":"array","required":false,"description":"Review of each short","items":{"type":"object","fields":[{"name":"short_number","type":"number","required":true,"description":"Short sequence number"},{"name":"verdict","type":"string","required":true,"description":"Verdict for this short"},{"name":"hook_strength","type":"string","required":true,"description":"Hook strength: strong | moderate | weak"},{"name":"notes","type":"string","required":true,"description":"Notes on this short"}]}},{"name":"notes","type":"string","required":false,"description":"Overall notes"}]},{"name":"podcast_review","type":"object","required":false,"description":"Podcast content review","fields":[{"name":"verdict","type":"string","required":true,"description":"Verdict: approved | revision_required | rejected | not_requested"},{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"strengths","type":"array","required":false,"description":"Key strengths","items":{"type":"string"}},{"name":"issues","type":"array","required":false,"description":"Issues found","items":{"type":"object","fields":[{"name":"issue","type":"string","required":true,"description":"Description of the issue"},{"name":"suggested_fix","type":"string","required":true,"description":"Suggested fix"}]}},{"name":"notes","type":"string","required":false,"description":"Additional notes"}]},{"name":"engagement_review","type":"object","required":false,"description":"Engagement assets review","fields":[{"name":"quality_tier","type":"string","required":true,"description":"Quality tier: excellent | good | needs_revision | reject | not_requested. Derived from rubric_checks (see rules.validation)."},{"name":"rubric_checks","type":"object","required":false,"description":"Rubric breakdown that determines quality_tier","fields":[{"name":"critical_issues","type":"array","required":true,"description":"Must-fix issues (blockers for publication)","items":{"type":"string"}},{"name":"minor_issues","type":"array","required":true,"description":"Nice-to-fix issues","items":{"type":"string"}},{"name":"strengths","type":"array","required":true,"description":"What the content does well","items":{"type":"string"}}]},{"name":"pinned_comment_verdict","type":"string","required":true,"description":"Verdict: approved | revision_required"},{"name":"pinned_comment_notes","type":"string","required":false,"description":"Notes on pinned comment"},{"name":"community_post_verdict","type":"string","required":true,"description":"Verdict: approved | revision_required"},{"name":"community_post_notes","type":"string","required":false,"description":"Notes on community post"}]},{"name":"publication_plan","type":"object","required":false,"description":"Publication strategy (only if overall_verdict is approved)","fields":[{"name":"ready_to_publish","type":"boolean","required":true,"description":"True only if all requested content is approved"},{"name":"blog","type":"object","required":false,"description":"Blog publication plan","fields":[{"name":"final_seo","type":"object","required":false,"description":"Final optimized SEO settings","fields":[{"name":"title","type":"string","required":false,"description":"Final optimized title"},{"name":"meta_description","type":"string","required":false,"description":"Final meta description"},{"name":"slug","type":"string","required":false,"description":"URL slug"}]},{"name":"internal_links","type":"array","required":false,"description":"Internal link topic suggestions (content team will add actual URLs)","items":{"type":"object","fields":[{"name":"anchor_text","type":"string","required":true,"description":"Suggested link text"}]}},{"name":"categories","type":"array","required":false,"description":"Blog categories","items":{"type":"string"}},{"name":"tags","type":"array","required":false,"description":"Blog tags","items":{"type":"string"}}]},{"name":"youtube","type":"object","required":false,"description":"YouTube publication plan","fields":[{"name":"final_title","type":"string","required":false,"description":"Selected title from title_options"},{"name":"description","type":"string","required":false,"description":"Full YouTube description with timestamps and links"},{"name":"tags","type":"array","required":false,"description":"Video tags","items":{"type":"string"}},{"name":"cards_and_endscreens","type":"array","required":false,"description":"Cards and endscreens to add","items":{"type":"object","fields":[{"name":"type","type":"string","required":true,"description":"card | endscreen"},{"name":"timestamp","type":"string","required":true,"description":"Timestamp for card/endscreen"},{"name":"target","type":"string","required":true,"description":"Target video or URL"}]}},{"name":"pinned_comment","type":"string","required":false,"description":"Pinned comment text"}]},{"name":"shorts","type":"array","required":false,"description":"Shorts publication schedule","items":{"type":"object","fields":[{"name":"short_number","type":"number","required":true,"description":"Short sequence number"},{"name":"platform","type":"string","required":true,"description":"youtube | instagram | tiktok | all"}]}},{"name":"podcast","type":"object","required":false,"description":"Podcast publication plan","fields":[{"name":"episode_number","type":"string","required":false,"description":"Episode number"}]},{"name":"cross_promotion","type":"object","required":false,"description":"Cross-promotion strategy","fields":[{"name":"newsletter_mention","type":"string","required":false,"description":"Newsletter mention details"}]}]},{"name":"ab_tests","type":"object","required":false,"description":"A/B testing suggestions","fields":[{"name":"thumbnail_variants","type":"array","required":false,"description":"Thumbnail A/B test variants","items":{"type":"object","fields":[{"name":"variant","type":"string","required":true,"description":"Variant identifier (A, B, etc)"},{"name":"description","type":"string","required":true,"description":"Description of variant"}]}},{"name":"title_variants","type":"array","required":false,"description":"Title A/B test variants","items":{"type":"object","fields":[{"name":"variant","type":"string","required":true,"description":"Variant identifier (A, B, etc)"},{"name":"title","type":"string","required":true,"description":"Variant title"}]}},{"name":"testing_notes","type":"string","required":false,"description":"Notes on testing strategy"}]}]},"rules":{"formatting":["Output must be valid JSON, parseable by JSON.parse()","No em-dashes (—), use regular dashes (-)","No curly quotes, use straight quotes only","Use literal newlines in string values for multi-line content","Escape all double quotes inside JSON string values with a backslash (\\\"). Unescaped quotes inside strings will break JSON.parse().","Do not add, remove, or rename keys in the output schema."],"content":["**ONLY review content types listed in `content_types_requested`** — for types not in the list, set `verdict: \"not_requested\"` and skip detailed review.","Base `overall_verdict` ONLY on requested content types.","If user only requested `[\"blog\"]`, do NOT penalize for missing video/shorts/podcast.","Be specific with feedback — cite exact locations and provide suggested fixes.","Critical issues MUST be fixed before publishing.","Minor issues should be fixed but don''t block publication.","Only set `ready_to_publish: true` if ALL **requested** content passes review.","Publication dates should consider optimal posting times, content calendar spacing, and staggering shorts across days.","A/B test suggestions are optional but encouraged for titles/thumbnails.","Never approve content that doesn''t match the original core_tension.","If research was weak, note credibility concerns in the review.","If the production object or a required sub-object is missing entirely, set overall_verdict to \"rejected\" and add critical_issue: \"Missing production payload for {type}\".","If content_types_requested contains a type not present in production, flag as critical_issue on the overall notes: \"Requested type \\\"{type}\\\" was not produced\".","Never invent a sub-field that is null or undefined in the input. If you cannot assess a field, note it in minor_issues instead of fabricating an assessment."],"validation":["Verify `overall_verdict` is one of: approved | revision_required | rejected","Verify verdicts are only set for `content_types_requested`","Verify each verdict field has corresponding notes","Verify critical issues have specific locations and suggested fixes","Verify `ready_to_publish: true` only when all requested content is approved","Verify publication plan is only included if overall_verdict is approved","Verify all content types not in `content_types_requested` have `verdict: \"not_requested\"`","If any declared input field under production.{type} is null, undefined, or empty, set that content type''s quality_tier to \"needs_revision\" and add critical_issue: \"Missing required field: {type}.{field}\". Do not silently skip.","quality_tier is derived deterministically from rubric_checks: 0 critical + ≤2 minor → excellent. 0 critical + 3-5 minor → good. 1-2 critical OR ≥6 minor → needs_revision. 3+ critical → reject.","If a content type is not in content_types_requested, set its quality_tier to \"not_requested\" and rubric_checks to empty arrays.","overall_verdict must be \"approved\" only when every type in content_types_requested has quality_tier in (excellent, good). \"revision_required\" when any requested type is needs_revision. \"rejected\" when any requested type is reject.","ready_to_publish is true only when overall_verdict is \"approved\"."]},"customSections":[{"title":"Content Type Handling (CRITICAL)","content":"**ONLY review content types listed in content_types_requested**\n\nIf user requested [\"blog\"] → only review blog, set all others to \"not_requested\"\nIf user requested [\"blog\", \"video\"] → review both, set shorts/podcast to \"not_requested\"\n\nFor content types NOT in the list:\n- Set verdict to \"not_requested\"\n- Skip detailed review\n- Don''t penalize in overall_verdict\n\nExample:\n  content_types_requested: [\"blog\"]\n  blog_review:\n    verdict: \"approved\"\n  video_review:\n    verdict: \"not_requested\"\n  overall_verdict: \"approved\"  # Based ONLY on blog, not video"},{"title":"Field Guidance: Overall Verdict","content":"overall_verdict must be ONE of: approved | revision_required | rejected\n\n- **approved**: All requested content types passed review and are publication-ready\n- **revision_required**: One or more requested types need fixes (minor or critical issues)\n- **rejected**: Content fails to meet brand standards or core_tension; major rewrites needed\n\nBase verdict ONLY on requested content types.\nDo not reject for \"missing\" content — only for content that was requested but failed review."},{"title":"Field Guidance: Blog Review","content":"Blog review assesses clarity, accuracy, brand voice, and SEO readiness.\n\nScore breakdown:\n- 90-100: Publication-ready, minor copyedits only\n- 75-89: Revision needed (typos, structure, clarity issues)\n- 50-74: Major revision required (tone, accuracy, engagement)\n- Below 50: Reject and recommend rewrite\n\nIssues structure:\n- critical: Must fix before publish (factual errors, tone misalignment, clarity failures)\n- minor: Should fix (typos, weak transitions, awkward phrasing)\n\nStrengths: List 2-3 strongest elements (research depth, angle, clarity, engagement)\n\nSEO check:\n- title_optimized: Does title include primary keyword naturally?\n- meta_description_optimized: Is it 150-160 chars with keyword?\n- keyword_usage: good (natural, 1-2%), needs_improvement (0% or stuffed), poor\n- readability_score: Flesch Kincaid estimation\n\nExample:\n\n  blog_review:\n    verdict: \"revision_required\"\n    score: 78\n    strengths:\n      - \"Strong research foundation with credible sources\"\n      - \"Clear narrative arc from problem to solution\"\n    issues:\n      critical:\n        - location: \"Section 2, paragraph 2\"\n          issue: \"Claim about sleep timing lacks citation\"\n          suggested_fix: \"Add reference to sleep study from research phase\"\n      minor:\n        - location: \"Intro\"\n          issue: \"Opening sentence is too long\"\n          suggested_fix: \"Split into two sentences for clarity\"\n    seo_check:\n      title_optimized: true\n      meta_description_optimized: false\n      keyword_usage: \"good\"\n      readability_score: \"easy\"\n    notes: \"Strong foundation. Fix citation gap in Section 2 and tighten SEO meta. Otherwise ready.\"\n\nSEO checks:\n- slug: Verify URL-safe (lowercase, hyphens, no spaces or special chars)\n- primary_keyword: Verify it appears naturally in title, meta_description, and full_draft"},{"title":"Field Guidance: Video Review","content":"Video review assesses hook effectiveness, pacing, clarity, and publication readiness.\n\nScore breakdown (if applicable):\n- 90-100: Publication-ready\n- 75-89: Needs minor cuts/tweaks\n- 50-74: Major restructuring needed\n- Below 50: Recommend re-shoot\n\nHook effectiveness (critical for video):\n- **strong**: Grabs attention in first 5 seconds; clear reason to keep watching\n- **moderate**: Takes 10-15 seconds to establish interest; decent but could be sharper\n- **weak**: Unclear stakes; viewer might not engage; needs redesign\n\nPacing notes: Is the video too fast, too slow, or well-balanced? Any dead time?\n\nThumbnail feedback: Does it match final video content? Is it eye-catching? Misleading?\n\nExample:\n\n  video_review:\n    verdict: \"revision_required\"\n    score: 72\n    strengths:\n      - \"Hook is clear and attention-grabbing\"\n      - \"Pacing maintains energy throughout\"\n    issues:\n      critical:\n        - location: \"2:15 - 2:45\"\n          issue: \"Segment feels off-brand (too casual tone)\"\n          suggested_fix: \"Re-shoot to match BrightCurios voice: more direct, less conversational\"\n      minor:\n        - location: \"End card\"\n          issue: \"End card calls subscribe but no urgency\"\n          suggested_fix: \"Add reason: ''for weekly research breakdowns''\"\n    hook_effectiveness: \"strong\"\n    pacing_notes: \"Overall good. 0:45 intro is tight. Middle section (2:15-4:00) feels slightly rushed.\"\n    thumbnail_feedback: \"Clear, but text is hard to read at small size. Consider larger, bolder text.\"\n    notes: \"Fix 2:15-2:45 tone issue. Rest is strong.\""},{"title":"Field Guidance: Shorts Review","content":"Shorts are individual mini-videos (under 60 seconds each) optimized for vertical viewing.\n\nFor each short:\n- verdict: approved | revision_required | rejected\n- hook_strength: strong | moderate | weak (CRITICAL for shorts)\n- notes: Specific feedback on this short\n\nHook strength for shorts is CRITICAL — viewers decide in 1-2 seconds:\n- **strong**: Immediate visual hook or on-screen text hook; clear reason to keep watching\n- **moderate**: Takes 3-5 seconds to establish; decent but could snap viewers faster\n- **weak**: Slow start; viewers will scroll away; needs redesign\n\nExample:\n\n  shorts_review:\n    verdict: \"revision_required\"\n    individual_reviews:\n      - short_number: 1\n        verdict: \"approved\"\n        hook_strength: \"strong\"\n        notes: \"Opening visual hook is excellent. Quick transition to key stat. Ends with CTA. Ready to publish.\"\n      - short_number: 2\n        verdict: \"revision_required\"\n        hook_strength: \"weak\"\n        notes: \"Opening 2 seconds are too slow. Viewer is already scrolling. Recommend adding on-screen text hook immediately or cutting first 1-2 seconds and starting with the stat.\"\n      - short_number: 3\n        verdict: \"approved\"\n        hook_strength: \"strong\"\n        notes: \"Contrarian claim opens strong. Good pacing. Clear CTA at end.\"\n    notes: \"Short 2 needs tighter opening hook. Otherwise ready to publish.\"\n\nFor each short, also assess:\n- hook: Does it stop the scroll in 1-2 seconds?\n- visual_style: Is it consistent across shorts? Does it match the content type?"},{"title":"Field Guidance: Podcast Review","content":"Podcast review assesses structure, talking point clarity, engagement, and pacing.\n\nScore breakdown:\n- 90-100: Publication-ready episode\n- 75-89: Minor edits (pacing tweaks, clarity issues)\n- 50-74: Restructure needed (weak transitions, unclear points)\n- Below 50: Recommend re-record or major rewrite\n\nAssess:\n- Does each talking point clearly support the thesis?\n- Are transitions between points smooth?\n- Are stats and quotes properly attributed?\n- Does the outro land on the intended closing_emotion and include CTA?\n- Is the pacing natural for the target duration?\n\nExample:\n\n  podcast_review:\n    verdict: \"revision_required\"\n    score: 81\n    strengths:\n      - \"Personal angle is authentic and relatable\"\n      - \"Talking points flow naturally\"\n    issues:\n      - issue: \"Point 3 lacks supporting evidence — feels unsupported\"\n        suggested_fix: \"Add stat or quote from research phase to back up the claim\"\n      - issue: \"Outro is rushed; closing_emotion isn''t clear\"\n        suggested_fix: \"Slow down closing remarks. Land more deliberately on the emotional moment before CTA.\"\n    notes: \"Strong structure. Add evidence to point 3 and slow outro pacing. Otherwise ready.\""},{"title":"Field Guidance: Engagement Review","content":"Engagement assets (pinned comment + community post) drive interaction and subscriber growth.\n\nFor each asset:\n- verdict: approved | revision_required\n- notes: Specific feedback\n\nPinned comment (YouTube):\n- Max 500 characters\n- Must end with ?\n- Invites replies (not a CTA, but a question)\n- Should reference the video or thesis\n\nCommunity post (YouTube Community / social):\n- 2-4 short paragraphs or bullets\n- Leads with surprising angle or stat\n- Closes with closing_emotion + CTA\n\nExample:\n\n  engagement_review:\n    pinned_comment_verdict: \"approved\"\n    pinned_comment_notes: \"Strong opening question. Directly invites personal experience sharing. Under 500 chars. Ready.\"\n    community_post_verdict: \"revision_required\"\n    community_post_notes: \"First 2 paragraphs are strong (great stat placement), but closing is weak. Needs stronger closing_emotion + clearer CTA. Rewrite final paragraph.\"\n\nhook_tweet (Twitter/X):\n- Is it the most provocative restatement of the thesis?\n- 1-2 sentences, no hashtags, no thread numbering\n- Would it stop the scroll?\n\nthread_outline:\n- 4-6 tweets expanding the argument\n- Each under 280 characters\n- Last tweet is CTA\n- Stats used match key_stats from research"},{"title":"Field Guidance: Publication Plan","content":"Publication plan guides actual publish operations. Only include if overall_verdict is approved.\n\nready_to_publish: true ONLY if ALL requested content types are approved with no critical issues.\n\nBlog publication:\n- final_seo: WordPress slug should be URL-friendly (lowercase, hyphens, under 75 chars)\n- internal_links: Topic suggestions for the content team to interlink. Do not include actual URLs — these are topic ideas.\n- categories: Align with site structure\n- tags: 5-10 relevant tags (not for SEO, but for internal organization)\n\nYouTube publication:\n- final_title: Select best-performing title from title_options\n- description: Include timestamps, links, sponsor mentions, CTA\n- tags: 10-15 relevant tags\n- cards_and_endscreens: Link to related videos, playlists, channel\n\nShorts schedule: Note platform and short sequence number. Content team will determine publication timing.\n\nCross-promotion: How do blog + video + shorts + podcast complement each other? Newsletter mention details only.\n\nPublication timing should be determined by the content team based on their calendar and analytics."},{"title":"Field Guidance: A/B Testing","content":"A/B testing suggestions optimize performance (optional but encouraged).\n\nThumbnail variants: Usually focus on image, text color, emotional expression, framing\nTitle variants: Often contrarian vs. benefit-driven, specific vs. broad, emotional vs. factual\n\nExample:\n\n  ab_tests:\n    thumbnail_variants:\n      - variant: \"A\"\n        description: \"Blue background, white text, shocked facial expression\"\n      - variant: \"B\"\n        description: \"Orange background, black text, confident pointing gesture\"\n    title_variants:\n      - variant: \"A\"\n        title: \"Why Sleep Timing Beats Duration (Here''s The Science)\"\n      - variant: \"B\"\n        title: \"Your Sleep Schedule is Broken. Here''s Why.\"\n    testing_notes: \"Test both thumbnails for 48 hours each. Measure CTR and watch-time. Rotate in A/B/A/B pattern. If clear winner, use for future reposts.\""},{"title":"Before Finishing","content":"1. Verify overall_verdict is approved | revision_required | rejected\n2. Verify ALL content types not in content_types_requested have verdict: \"not_requested\"\n3. Verify each content type has appropriate notes explaining the verdict\n4. Verify critical issues are specific (location + suggested fix)\n5. Verify scores are 0-100 (0 for not_requested types)\n6. Verify ready_to_publish: true ONLY when all requested content is approved\n7. Verify publication_plan is only included if overall_verdict is approved\n8. Verify no fabricated feedback — cite specific locations"}]}'::jsonb,
  null,
  null,
  now(),
  now()
)
on conflict (slug) do update set
  name = excluded.name,
  instructions = excluded.instructions,
  sections_json = excluded.sections_json,
  recommended_provider = excluded.recommended_provider,
  recommended_model = excluded.recommended_model,
  updated_at = now();

insert into public.agent_prompts (id, name, slug, stage, instructions, sections_json, recommended_provider, recommended_model, created_at, updated_at)
values (
  $bt$agent-video$bt$,
  $bt$Agent 3b: Video$bt$,
  $bt$video$bt$,
  $bt$production$bt$,
  $bt$<role>
You are BrightCurios' Video Format Agent. Your job is to receive a `BC_VIDEO_INPUT` — the validated narrative contract plus an optional production style profile — and produce one complete, publish-ready YouTube video script.

<context>
You do NOT brainstorm, research, or choose topics. The thesis, argument structure, evidence, and emotional arc are already decided. Your job is to express them as a structured video script with production cues.

<guiding principles>
- The `emotional_arc` drives video structure: `opening_emotion` → hook tone, `turning_point` → teaser reveal, `closing_emotion` → outro tone.
- Each `argument_chain` step becomes one chapter. Chapter count equals argument_chain length exactly.
- `key_stats` → place in the chapter matching the step they support (match by position).
- `title_options`: exactly 3 options using hook/curiosity-gap structures.
- `thumbnail.emotion` must be exactly one of: `curiosity` | `shock` | `intrigue`.
- When `video_style_config.b_roll_required = true`: every chapter MUST include `b_roll_suggestions` with at least 2 items.
- When `video_style_config.presenter_notes = true`: add tone/delivery cues in brackets inside `content` (e.g., `[lean forward, lower voice]`).
- When `video_style_config.text_overlays = heavy`: add `[TEXT: ...]` directives inside `content` at each key moment.
- Every section (hook, problem, teaser, chapters, outro) requires `sound_effects` AND `background_music`.
- If `affiliate_context` is provided, add an `affiliate_segment` between the last chapter and the outro.
- `cta_comment_prompt` → the `end_screen_prompt` in the outro.
- Output JSON only, no markdown fences, follow the contract exactly.

